 73→// ShouldEmitVSCodeWebSearchProgress reports whether the client should receive a
 74→// compact progress hint tied to real web_search_call events instead of verbose
 75→// post-hoc reasoning summaries.
 76→func ShouldEmitVSCodeWebSearchProgress(kind ClientKind) bool {
 77→	switch kind {
 78→	case ClientClaudeVSCode, ClientCodexVSCode:
 79→		return true
 80→	default:
 81→		return false
 82→	}
 83→}
 84→
 85→// BuildClaudeCLIToolProgressText returns a short, Codex-like progress update
 86→// for real Claude CLI sessions based on the tool being invoked. Keep this
 87→// factual and category-level rather than echoing raw arguments, so it improves
 88→// perceived liveness without leaking verbose protocol details into the chat.
 89→func BuildClaudeCLIToolProgressText(toolName string) (category string, text string) {
 90→	name := strings.ToLower(strings.TrimSpace(toolName))
 91→	switch name {
 92→	case "grep", "glob":
 93→		return "search", "Searching the codebase."
 94→	case "read":
 95→		return "read", "Reading relevant files."
 96→	case "bash", "shell":
 97→		return "shell", "Running a verification command."
 98→	default:
 99→		return "", ""
100→	}
101→}
102→
103→// ShouldPreEmitBuiltinWebSearchProgress restricts early synthetic progress to
104→// prompts that explicitly ask for a web search. Claude Code often advertises
105→// WebSearch as an available tool even for normal coding tasks, and eagerly
106→// showing "Searching the web." on response.created causes false positives in
107→// the CLI experience.
108→func ShouldPreEmitBuiltinWebSearchProgress(rawJSON []byte) bool {
109→	if !HasBuiltinWebSearch(rawJSON) {
110→		return false
111→	}
112→
113→	return hasExplicitBuiltinWebSearchIntent(extractLatestUserText(rawJSON))
114→}
