116→// BuildVSCodeWebSearchProgressThinking renders a short, factual progress message
117→// for VSCode-style clients. Unlike synthetic <tool_call> text, this keeps the
118→// UI concise and avoids leaking implementation details into the chat transcript.
119→func BuildVSCodeWebSearchProgressThinking(action gjson.Result, fallbackQuery string) string {
120→	switch strings.ToLower(strings.TrimSpace(action.Get("type").String())) {
121→	case "search":
122→		query := strings.TrimSpace(action.Get("query").String())
123→		if query == "" {
124→			query = strings.TrimSpace(fallbackQuery)
125→		}
126→		if query != "" {
127→			return "Searching the web for: " + query
128→		}
